SELECT COUNT(ad_event_id) AS ad_count
FROM advertisement_events
WHERE user_id = 0;

SELECT *
FROM stream_metrics
ORDER BY bitrate DESC;

SELECT stream_id
FROM error_events
WHERE user_id = 1;

SELECT COUNT(error_id) AS total_errors
FROM error_events
WHERE user_id = 1;

SELECT stream_id, COUNT(ad_event_id) AS ad_count
FROM advertisement_events
GROUP BY stream_id;

SELECT stream_id
FROM stream_metrics
WHERE bitrate = (SELECT MAX(bitrate) FROM stream_metrics);
